func (o *User) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "ChatConversations":
		rels, ok := retrieved.(ChatConversationSlice)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.ChatConversations = rels
		o.R.Loaded.ChatConversations = true

		return nil
	case "ConnectionAccesses":
		rels, ok := retrieved.(ConnectionAccessSlice)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.ConnectionAccesses = rels
		o.R.Loaded.ConnectionAccesses = true

		return nil
	case "Connections":
		rels, ok := retrieved.(ConnectionSlice)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.Connections = rels
		o.R.Loaded.Connections = true

		return nil
	case "RefreshTokens":
		rels, ok := retrieved.(RefreshTokenSlice)
		if !ok {
			return fmt.Errorf("user cannot load %T as %q", retrieved, name)
		}

		o.R.RefreshTokens = rels
		o.R.Loaded.RefreshTokens = true

		return nil
	default:
		return fmt.Errorf("user has no relationship %q", name)
	}
}

