type userJoins[Q dialect.Joinable] struct {
	typ                string
	ChatConversations  modAs[Q, chatConversationColumns]
	ConnectionAccesses modAs[Q, connectionAccessColumns]
	Connections        modAs[Q, connectionColumns]
	RefreshTokens      modAs[Q, refreshTokenColumns]
}

func (j userJoins[Q]) aliasedAs(alias string) userJoins[Q] {
	return buildUserJoins[Q](buildUserColumns(alias), j.typ)
}

func buildUserJoins[Q dialect.Joinable](cols userColumns, typ string) userJoins[Q] {
	return userJoins[Q]{
		typ: typ,
		ChatConversations: modAs[Q, chatConversationColumns]{
			c: ChatConversations.Columns,
			f: func(to chatConversationColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, ChatConversations.Name().As(to.Alias())).On(
						to.UserID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		ConnectionAccesses: modAs[Q, connectionAccessColumns]{
			c: ConnectionAccesses.Columns,
			f: func(to connectionAccessColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, ConnectionAccesses.Name().As(to.Alias())).On(
						to.UserID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Connections: modAs[Q, connectionColumns]{
			c: Connections.Columns,
			f: func(to connectionColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Connections.Name().As(to.Alias())).On(
						to.UserID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		RefreshTokens: modAs[Q, refreshTokenColumns]{
			c: RefreshTokens.Columns,
			f: func(to refreshTokenColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, RefreshTokens.Name().As(to.Alias())).On(
						to.UserID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
